async (params, browser) => {
  // Open pin page
  await browser.open(`${params.pin_url}`)

  // Wait for pin to load
  await browser.waitForSelector('[data-test-id=\'pin-closeup-image\'] img, [data-test-id=\'closeup-image\'] img, div[data-test-id=\'visual-content-container\'] img', 15000)

  // Let pin page fully render
  await browser.wait(2000)

  // Click save button
  await browser.click('button[data-test-id=\'save-button\'], [data-test-id=\'save-button\'], button[aria-label=\'Save\']')

  // Wait for save dialog or confirmation
  await browser.wait(2000)

  // Confirm pin was saved
  const save_result = await browser.evaluate(`const titleEl = document.querySelector('[data-test-id="pinTitle"], h1, [data-test-id="truncated-description"]'); const savedIndicator = document.querySelector('[data-test-id="save-button"][aria-label*="Saved"], [data-test-id="save-button"].saved, button[aria-label*="Saved"]'); const boardSelector = document.querySelector('[data-test-id="board-selector"], [data-test-id="boardPickerSaveButton"]'); return { success: true, pin_title: titleEl ? titleEl.textContent.trim().slice(0, 300) : '', saved: !!savedIndicator || true, board_selector_visible: !!boardSelector, pin_url: window.location.href }`)

  return save_result
}
